html:
{% set company = frappe.get_doc('Company', doc.company) if doc.company else None %}
{% set owner_name = frappe.db.get_value('User', doc.owner, 'full_name') or doc.owner or '' %}
{% set _ca_link = doc.company_address or None %}
{% if company and not _ca_link %}
{% set _ca_link = frappe.call('erpnext.setup.doctype.company.company.get_default_company_address', name=company.name) %}
{% endif %}
{% set company_addr = frappe.get_doc('Address', _ca_link) if _ca_link else None %}
{% set ship_addr_doc = frappe.get_doc('Address', doc.shipping_address_name) if doc.get('shipping_address_name') else None %}
{% set _ship_raw = (doc.shipping_address or '').strip() %}
{% set _ship_from_doc = (ship_addr_doc.get_display() or '').strip() if ship_addr_doc else '' %}
{% set shipping_text = _ship_raw or _ship_from_doc or (doc.address_display or '').strip() %}
{% set billing_text = doc.address_display or '' %}
{% set ns_bill = namespace(lines=[]) %}
{% for line in (billing_text or '').splitlines() %}{% if line.strip() %}{% set _ = ns_bill.lines.append(line.strip()) %}{% endif %}{% endfor %}
{% set ns_ship = namespace(lines=[]) %}
{% for line in (shipping_text or '').splitlines() %}{% if line.strip() %}{% set _ = ns_ship.lines.append(line.strip()) %}{% endif %}{% endfor %}
{% set billing_addr_doc = frappe.get_doc('Address', doc.customer_address) if doc.get('customer_address') else None %}
{% set place_supply_display = (billing_addr_doc.get('state') if billing_addr_doc else '') or (doc.get('place_of_supply') or '') %}
{% set _po_gc = frappe.db.sql("SELECT GROUP_CONCAT(DISTINCT purchase_order SEPARATOR ', ') FROM `tabSales Order Item` WHERE parent=%s AND IFNULL(purchase_order,'') != ''", doc.name) %}
{% set po_linked = (_po_gc[0][0] if _po_gc and _po_gc[0] and _po_gc[0][0] else '') %}
{% set po_display = po_linked or (doc.get('inter_company_order_reference') or '') or (doc.po_no or '') %}
{% set site_name_obm = frappe.db.get_value('Offline Buyer Master', doc.custom_offline_buyer_master, 'site_name') if doc.get('custom_offline_buyer_master') else '' %}
{% set obm_doc = frappe.get_doc('Offline Buyer Master', doc.custom_offline_buyer_master) if doc.get('custom_offline_buyer_master') else None %}
{% set company_gst = '24AASCA1881A1ZV' %}
{% set ns_ca = namespace(lines=[], company_address_html=False) %}
{% if company_addr %}{% for line in (company_addr.get_display() or '').splitlines() %}{% if line.strip() %}{% set _ = ns_ca.lines.append(line.strip()) %}{% endif %}{% endfor %}
{% elif doc.get('company_address_display') %}{% for line in (doc.company_address_display or '').splitlines() %}{% if line.strip() %}{% set _ = ns_ca.lines.append(line.strip()) %}{% endif %}{% endfor %}
{% elif company and company.address_html %}{% set ns_ca.company_address_html = (company.address_html or '') %}
{% endif %}

{% set freebies = doc.custom_marketing_freebies or [] %}
{% set total_qty = doc.total_qty or 0 %}

<style>
  @page { size: A4; margin: 10mm; }
  .so-wrap { font-family: Arial, sans-serif; color: #000; font-size: 11px; width: 100%; }
  .so-table { width: 100%; border-collapse: collapse; table-layout: fixed; margin-bottom: -1px; }
  .so-table td, .so-table th { border: 1px solid #000; padding: 6px 8px; vertical-align: top; line-height: 1.4; word-wrap: break-word; overflow: visible !important; }

  .so-main-title { font-size: 24px; font-weight: 800; letter-spacing: 0.5px; padding: 8px 0 10px; }
  .center { text-align: center; }
  .left { text-align: left; }
  .right { text-align: right; }
  .bold { font-weight: 700; }
  .mt12 { margin-top: 12px; }

  .bg-grey { background-color: #fcfcfc; }
  .cell-label { font-weight: 700; display: block; margin-bottom: 2px; }

  /* Column widths */
  .col-sr { width: 5%; } .col-img { width: 9%; } .col-sku { width: 27%; } .col-qty { width: 8%; } 
  .col-uom { width: 8%; } .col-mrp { width: 10%; } .col-flat { width: 8%; } .col-offer { width: 8%; } .col-amt { width: 17%; }
</style>

<div class='so-wrap'>
  <div class='so-main-title center'>SALES ORDER</div>

  <!-- Header Table -->
  <table class='so-table'>
    <colgroup><col style='width:18%'><col style='width:34%'><col style='width:24%'><col style='width:24%'></colgroup>
    <tr>
      <td rowspan='2' class='center' style='vertical-align:middle; padding: 10px;'>
        {% if company and company.company_logo %}<img src='{{ frappe.utils.get_url(company.company_logo) }}' alt='' style='max-height:68px; max-width:100%;'>{% else %}LOGO{% endif %}
      </td>
      <td class='left bold' style='font-size: 14px; padding: 12px 8px;'>{{ company.company_name if company else '' }}</td>
      <td><span class='bold'>Sales Order #</span><br>{{ doc.name }}</td>
      <td><span class='bold'>Sales Date</span><br>{{ frappe.utils.formatdate(doc.transaction_date, 'dd-mm-yyyy') if doc.transaction_date else '' }}</td>
    </tr>
    <tr>
      <td class='left' style='padding: 8px 8px;'>
        <span class='bold'>GSTIN:</span> {{ company_gst }}<br>
        {% if company and company.phone_no %}<span class='bold'>Phone:</span> {{ company.phone_no }}<br>{% endif %}
        {% if company and company.email %}<span class='bold'>Email:</span> {{ company.email }}<br>{% endif %}
        {% if company and company.website %}<span class='bold'>Website:</span> {{ company.website.replace('https://','').replace('http://','') }}{% endif %}
      </td>
      <td><span class='bold'>Place of Supply</span><br>{{ place_supply_display }}</td>
      <td><span class='bold'>PO#</span><br>{{ po_display }}</td>
    </tr>
    <tr>
      <td colspan='2'><span class='bold'>Company Address</span><br>{% if ns_ca.company_address_html %}{{ ns_ca.company_address_html | safe }}{% else %}{% for line in ns_ca.lines %}{{ line }}{% if not loop.last %}<br>{% endif %}{% endfor %}{% endif %}</td>
      <td colspan='2'><span class='bold'>Created By</span><br>{{ owner_name }}</td>
    </tr>
  </table>

  <!-- Party Table -->
  <table class='so-table mt12'>
    <colgroup>
        <col style='width:25%'>
        <col style='width:25%'>
        <col style='width:50%'>
    </colgroup>
    <tr>
      <td colspan="2" class='bold bg-grey'>Order From:</td>
      <td class='bold bg-grey'>Ship To:</td>
    </tr>
    <tr>
      <td colspan="2"><span class='bold'>Buyer Name:</span> {{ doc.customer_name or doc.customer or '' }} <br> <span class='bold'>Site Name:</span> {{ site_name_obm or '—' }}</td>
      <td class='bold'>{{ doc.customer_name or '' }}</td>
    </tr>
    <tr>
      <td colspan="2" style="padding: 8px 8px 12px; height: 80px; vertical-align: top;">
          <span class='bold'>Buyer Billing Address</span><br>
          {% for line in ns_bill.lines %}{{ line }}{% if not loop.last %}<br>{% endif %}{% endfor %}
      </td>
      <td rowspan="3" style="vertical-align: top;">
          <span class='bold'>Buyer Shipping Address</span><br>
          {% for line in ns_ship.lines %}{{ line }}{% if not loop.last %}<br>{% endif %}{% endfor %}
      </td>
    </tr>
    <tr>
      <td class="center">
          <span class="cell-label">Phone:</span>
          {% if obm_doc and obm_doc.contact_no %}{{ obm_doc.contact_no }}
          {% elif doc.contact_mobile %}{{ doc.contact_mobile }}{% else %}—{% endif %}
      </td>
      <td class="center">
          <span class="cell-label">Email:</span>
          {% if obm_doc and obm_doc.email %}{{ obm_doc.email }}
          {% elif doc.contact_email %}{{ doc.contact_email }}{% else %}—{% endif %}
      </td>
    </tr>
    <tr>
      <td class="center">
          <span class="cell-label">GST Type:</span>
          {{ 'Registered' if doc.tax_id else 'Unregistered' }}
      </td>
      <td class="center">
          <span class="cell-label">GSTIN:</span>
          {{ doc.tax_id or '—' }}
      </td>
    </tr>
  </table>

  <!-- Items Table -->
  <table class='so-table mt12'>
    <colgroup>
        <col class="col-sr"><col class="col-img"><col class="col-sku"><col class="col-qty">
        <col class="col-uom"><col class="col-mrp"><col class="col-flat"><col class="col-offer"><col class="col-amt">
    </colgroup>
    <thead>
    <tr><th colspan='9' class='center bg-grey'>ORDER ITEMS</th></tr>
    <tr>
      <th class='center'>Sr.</th>
      <th class='center'>Image</th>
      <th>SKU - SKU Name</th>
      <th class='center'>QTY</th>
      <th class='center'>UOM</th>
      <th class='right'>MRP</th>
      <th class='right'>Flat %</th>
      <th class='right'>Offer %</th>
      <th class='right'>Amount</th>
    </tr>
    </thead>
    <tbody>
    {% for row in doc.items %}
    <tr>
      <td class='center'>{{ row.idx }}</td>
      <td class='center'>{% if row.custom_product_image %}<img src='{{ frappe.utils.get_url(row.custom_product_image) }}' alt='' style='max-height:50px; max-width:100%;'>{% endif %}</td>
      <td>{{ row.item_code or '' }}{% if row.item_name %} - {{ row.item_name }}{% endif %}</td>
      <td class='center'>{{ frappe.utils.fmt_money(row.qty or 0, precision=0).replace('.00','') }}</td>
      <td class='center'>{{ row.uom or '' }}</td>
      <td class='right'>{{ frappe.utils.fmt_money(row.custom_customer_mrp or 0, currency=doc.currency) }}</td>
      <td class='right'>{{ row.custom_flat_discount or 0 }}</td>
      <td class='right'>{{ row.custom_offer or 0 }}</td>
      <td class='right'>{{ frappe.utils.fmt_money(row.amount or 0, currency=doc.currency) }}</td>
    </tr>
    {% endfor %}
    </tbody>
    <tfoot>
    <tr><td colspan='8' class='right bold'>Sub Total</td><td class='right'>{{ frappe.utils.fmt_money(doc.total or 0, currency=doc.currency) }}</td></tr>
    <tr><td colspan='8' class='right bold'>Cash Dis. (INR)</td><td class='right'>{{ frappe.utils.fmt_money(doc.custom_cash_discount_amount or 0, currency=doc.currency) }}</td></tr>
    <tr><td colspan='8' class='right bold' style="font-size: 13px;">Grand Total</td><td class='right bold' style="font-size: 13px;">{{ frappe.utils.fmt_money(doc.grand_total or 0, currency=doc.currency) }}</td></tr>
    <tr><td colspan='9' class='bold' style='padding:8px; background-color: #fcfcfc;'>Total PCS: {{ frappe.utils.flt(total_qty, 0) }} ({{ doc.items|length if doc.items else 0 }} Items)</td></tr>
    </tfoot>
  </table>

  <!-- Sub Tables -->
  {% if freebies %}
  <table class='so-table mt12'>
    <colgroup><col style="width:10%"><col style="width:35%"><col style="width:10%"><col style="width:45%"></colgroup>
    <thead>
    <tr><th colspan='4' class='center bg-grey'>Marketing Freebies</th></tr>
    <tr><th class="center">Sr.</th><th>SKU - SKU Name</th><th class="center">QTY</th><th>Remarks</th></tr>
    </thead>
    <tbody>
    {% for r in freebies %}{% if r.item_code %}
    <tr><td class="center">{{ loop.index }}</td><td>{{ r.item_code or '' }} - {{ r.item_name or '' }}</td><td class='center'>{{ r.qty or '' }}</td><td>{{ r.remarks or '' }}</td></tr>
    {% endif %}{% endfor %}
    </tbody>
  </table>
  {% endif %}

  {% set _sch = namespace(show=false) %}
  {% for r in doc.custom_scheme_item_table or [] %}{% if r.item_code %}{% set _sch.show = true %}{% endif %}{% endfor %}
  {% if _sch.show %}
  <table class='so-table mt12'>
    <colgroup><col style="width:10%"><col style="width:35%"><col style="width:10%"><col style="width:45%"></colgroup>
    <thead>
    <tr><th colspan='4' class='center bg-grey'>Scheme Details</th></tr>
    <tr><th class="center">Sr.</th><th>SKU - SKU Name</th><th class="center">QTY</th><th>Scheme</th></tr>
    </thead>
    <tbody>
    {% set _schn = namespace(n=0) %}
    {% for r in doc.custom_scheme_item_table or [] %}
    {% if r.item_code %}
    {% set _schn.n = _schn.n + 1 %}
    <tr><td class="center">{{ _schn.n }}</td><td>{{ r.item_code or '' }}{% if r.item_name %} - {{ r.item_name }}{% endif %}</td><td class='center'>{{ frappe.utils.fmt_money(r.qty or 0, precision=0).replace('.00','') }}</td><td>{{ r.scheme or '' }}</td></tr>
    {% endif %}
    {% endfor %}
    </tbody>
  </table>
  {% endif %}

  {% set _dmg = namespace(show=false) %}
  {% for r in doc.custom_additional_units_damage_items or [] %}{% if r.item_code %}{% set _dmg.show = true %}{% endif %}{% endfor %}
  {% if _dmg.show %}
  <table class='so-table mt12'>
    <colgroup><col style="width:8%"><col style="width:28%"><col style="width:10%"><col style="width:22%"><col style="width:32%"></colgroup>
    <thead>
    <tr><th colspan='5' class='center bg-grey'>Additional Details</th></tr>
    <tr><th class="center">Sr.</th><th>SKU - SKU Name</th><th class="center">QTY</th><th>Previous Order #</th><th>Remarks</th></tr>
    </thead>
    <tbody>
    {% set _dn = namespace(n=0) %}
    {% for r in doc.custom_additional_units_damage_items or [] %}
    {% if r.item_code %}
    {% set _dn.n = _dn.n + 1 %}
    <tr><td class="center">{{ _dn.n }}</td><td>{{ r.item_code or '' }}{% if r.item_name %} - {{ r.item_name }}{% endif %}</td><td class='center'>{{ frappe.utils.fmt_money(r.qty or 0, precision=0).replace('.00','') }}</td><td>{{ r.previous_order_id or '' }}</td><td>{{ r.remarks or '' }}</td></tr>
    {% endif %}
    {% endfor %}
    </tbody>
  </table>
  {% endif %}

  <!-- Final Footer -->
  <table class='so-table mt12' style="page-break-inside: avoid;">
    <tr><th colspan='2' class='center bg-grey'>Bank Details</th></tr>
    <tr><td style='width:35%;' class='bold'>Bank Name</td><td>Axis Bank Ltd.</td></tr>
    <tr><td class='bold'>Branch</td><td>Surat</td></tr>
    <tr><td class='bold'>Account Name</td><td>Alpino Health Foods Pvt. Ltd.</td></tr>
    <tr><td class='bold'>Account Number</td><td>919020040914629</td></tr>
    <tr><td class='bold'>IFSC Code</td><td>UTIB0000047</td></tr>
  </table>

  <table class='so-table mt12' style="page-break-inside: avoid;">
    <tr><td class='center'>Subject to Surat Jurisdiction only.</td></tr>
    <tr><td class='center bold' style="font-size: 12px; padding: 12px;">Thank you for helping making India Protein Sufficient Nation!</td></tr>
  </table>
</div>
